from flask import Flask, jsonify
import pymysql
from pymemcache.client.base import Client as MemcachedClient

app = Flask(__name__)

memcached_client = MemcachedClient('localhost', 11211)

# Connect to database
db = pymysql.connect(
    host='your_host',
    user='your_username',
    password='your_password',
    db='your_database'
)

def cache_results(ttl):
    def decorator(func):
        def wrapper(*args, **kwargs):
            key = f"{func.__name__}:{str(args)}:{str(kwargs)}"
            result = memcached_client.get(key)
            if result is not None:
                return result
            else:
                result = func(*args, **kwargs)
                memcached_client.set(key, result, expire=ttl)
                return result
        return wrapper
    return decorator

@app.route('/api/data', methods=['GET'])
@cache_results(ttl=3600)  # cache for 1 hour
def get_data():
    cursor = db.cursor()
    cursor.execute('SELECT * FROM your_table')
    data = cursor.fetchall()
    return jsonify(data)

if __name__ == '__main__':
    app.run(debug=True)